COMMENT ON TABLE mes_shift_handover IS 'Shift handover log per machine.';
CREATE INDEX IF NOT EXISTS idx_mshh_equip ON mes_shift_handover (equipment_id, handover_date DESC);

-- ---------------------------------------------------------------------------
