CREATE INDEX IF NOT EXISTS idx_pm_equipment_criticality ON pm_equipment_master (criticality);

CREATE TABLE IF NOT EXISTS pm_maintenance_plans (
    maintenance_plan_id         UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
