-- ============================================================================
-- HESEM MOM - Runtime Identifier and State Contract Alignment
-- ============================================================================
-- Purpose:
--   Align authority schema with actual runtime contracts for MES records whose
--   public identifiers are generated as stable alphanumeric document IDs by the
--   backend/API layer.  Keep strict typing where it represents a true controlled
--   value set, but do not coerce business IDs into UUIDs when the system already
--   uses readable immutable IDs.
--
-- Data safety:
--   All changes are type-widening or additive.  Existing values are preserved.
-- ============================================================================

ALTER TABLE departments
    ALTER COLUMN color TYPE VARCHAR(64) USING color::text;

ALTER TYPE material_consumption_type ADD VALUE IF NOT EXISTS 'VERIFY';

ALTER TABLE mes_material_consumption
    ALTER COLUMN consumption_id TYPE VARCHAR(80) USING consumption_id::text;

ALTER TABLE mes_genealogy_operations
    DROP CONSTRAINT IF EXISTS mes_genealogy_operations_genealogy_id_fkey;

ALTER TABLE mes_part_genealogy
    ALTER COLUMN genealogy_id TYPE VARCHAR(80) USING genealogy_id::text;

ALTER TABLE mes_genealogy_operations
    ALTER COLUMN genealogy_id TYPE VARCHAR(80) USING genealogy_id::text;

ALTER TABLE mes_genealogy_operations
    ADD CONSTRAINT mes_genealogy_operations_genealogy_id_fkey
    FOREIGN KEY (genealogy_id) REFERENCES mes_part_genealogy(genealogy_id);

ALTER TABLE mes_shift_handover
    ALTER COLUMN handover_id TYPE VARCHAR(80) USING handover_id::text,
    ALTER COLUMN machine_state TYPE VARCHAR(40) USING machine_state::text;

ALTER TABLE mes_shift_handover
    DROP CONSTRAINT IF EXISTS chk_mes_shift_handover_machine_state_runtime;

ALTER TABLE mes_shift_handover
    ADD CONSTRAINT chk_mes_shift_handover_machine_state_runtime
    CHECK (
        machine_state IS NULL
        OR lower(machine_state) IN (
            'running',
            'setup',
            'inspection',
            'on_hold',
            'down',
            'idle',
            'maintenance',
            'offline',
            'productive',
            'standby',
            'engineering',
            'scheduled_down',
            'unscheduled_down',
            'non_scheduled'
        )
    );
-- <<< END MIGRATION: 096_runtime_identifier_and_state_contract_alignment.sql

-- >>> BEGIN MIGRATION: 097_idempotency_replay_ledger.sql
-- ============================================================================
-- Migration 097: Idempotency Replay Ledger
-- ============================================================================
-- Purpose:
--   Promote mutation idempotency replay state from volatile/file-backed stores
--   into a PostgreSQL authoritative ledger. The application uses this table
--   whenever the existing PostgreSQL mode is enabled.
--
-- Data safety:
--   Additive migration only. Existing file-backed replay records remain on disk
--   for compatibility/forensics but are not imported automatically because their
--   TTL-bound semantics are request-local and safe to expire naturally.
--
-- Rollback:
--   DROP TABLE IF EXISTS idempotency_replay_ledger CASCADE;
-- ============================================================================

BEGIN;

CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS idempotency_replay_ledger (
    ledger_id          UUID         PRIMARY KEY DEFAULT uuid_generate_v4(),
    scope_key          TEXT         NOT NULL,
    scope_key_hash     CHAR(64)     NOT NULL,
    idempotency_key    VARCHAR(255) NOT NULL,
    fingerprint_hash   CHAR(64)     NOT NULL,
    status             VARCHAR(32)  NOT NULL DEFAULT 'in_progress'
        CHECK (status IN ('in_progress', 'completed', 'failed')),
    status_code        INT,
    response_payload   JSONB        NOT NULL DEFAULT '{}'::jsonb,
    metadata           JSONB        NOT NULL DEFAULT '{}'::jsonb,
    lock_owner         VARCHAR(80),
    error_class        TEXT,
    error_message      TEXT,
    created_at         TIMESTAMPTZ  NOT NULL DEFAULT now(),
    updated_at         TIMESTAMPTZ  NOT NULL DEFAULT now(),
    completed_at       TIMESTAMPTZ,
    expires_at         TIMESTAMPTZ  NOT NULL
);

ALTER TABLE idempotency_replay_ledger
    ALTER COLUMN scope_key TYPE TEXT;

ALTER TABLE idempotency_replay_ledger
    ADD COLUMN IF NOT EXISTS scope_key_hash CHAR(64);

UPDATE idempotency_replay_ledger
SET scope_key_hash = encode(digest(scope_key, 'sha256'), 'hex')
WHERE scope_key_hash IS NULL;

ALTER TABLE idempotency_replay_ledger
    ALTER COLUMN scope_key_hash SET NOT NULL;

ALTER TABLE idempotency_replay_ledger
    DROP CONSTRAINT IF EXISTS idempotency_replay_ledger_scope_key_idempotency_key_key;

CREATE UNIQUE INDEX IF NOT EXISTS ux_idempotency_replay_scope_hash_key
    ON idempotency_replay_ledger (scope_key_hash, idempotency_key);

CREATE INDEX IF NOT EXISTS idx_idempotency_replay_status
    ON idempotency_replay_ledger (status, updated_at);

CREATE INDEX IF NOT EXISTS idx_idempotency_replay_expires
    ON idempotency_replay_ledger (expires_at);

CREATE INDEX IF NOT EXISTS idx_idempotency_replay_scope
    ON idempotency_replay_ledger (scope_key);

COMMENT ON TABLE idempotency_replay_ledger IS
    'Authoritative mutation idempotency replay ledger for DB-enabled runtime.';

COMMENT ON COLUMN idempotency_replay_ledger.scope_key IS
    'Mutation scope, normally domain/table/action/business identity.';

COMMENT ON COLUMN idempotency_replay_ledger.scope_key_hash IS
    'SHA-256 hash of scope_key; this is the unique authority for long process-scope keys.';

COMMENT ON COLUMN idempotency_replay_ledger.idempotency_key IS
    'Client key or derived retry-window key supplied by the API idempotency resolver.';

COMMENT ON COLUMN idempotency_replay_ledger.fingerprint_hash IS
    'SHA-256 hash of the normalized request fingerprint.';

COMMENT ON COLUMN idempotency_replay_ledger.lock_owner IS
    'Transient owner token for the process that claimed in-progress execution.';

COMMIT;
-- <<< END MIGRATION: 097_idempotency_replay_ledger.sql

-- >>> BEGIN MIGRATION: 098_canonical_manufacturing_event_backbone.sql
-- ============================================================================
-- Migration 098: Canonical Manufacturing Event Backbone
-- ============================================================================
-- Purpose:
--   Add an immutable operational event ledger that can carry production,
--   inspection, NCR/CAPA, evidence, approval, and genealogy relation events
--   through one canonical digital-thread read model.
--
-- Data safety:
--   Additive migration only. Existing event/audit/passport/genealogy tables are
--   not modified and can be progressively projected into this ledger later.
--
-- Rollback:
--   DROP TABLE IF EXISTS mes_operational_event_ledger CASCADE;
-- ============================================================================

BEGIN;

CREATE TABLE IF NOT EXISTS mes_operational_event_ledger (
    event_id                    VARCHAR(120) PRIMARY KEY,
    event_type                  VARCHAR(80)  NOT NULL
        CHECK (event_type IN (
            'order.work_execution',
            'quality.inspection',
            'quality.ncr_capa_linkage',
            'evidence.attachment',
            'approval.decision',
            'trace.genealogy_relation'
        )),
    event_category              VARCHAR(40)  NOT NULL
        CHECK (event_category IN ('order', 'quality', 'evidence', 'approval', 'trace')),
    event_version               VARCHAR(20)  NOT NULL DEFAULT '1.0',
    payload_schema_version      VARCHAR(30)  NOT NULL DEFAULT '1.0',
    fingerprint_hash            CHAR(64)     NOT NULL,
    event_hash                  CHAR(64)     NOT NULL UNIQUE,
    previous_event_hash         CHAR(64),

    correlation_id              VARCHAR(120) NOT NULL,
    request_id                  VARCHAR(120),
    causation_event_id          VARCHAR(120),
    traceparent                 VARCHAR(255),

    enterprise_id               VARCHAR(80),
    company_id                  VARCHAR(80),
    site_id                     VARCHAR(80),
    plant_id                    VARCHAR(80),
    org_company_code            VARCHAR(30),
    org_legal_entity_code       VARCHAR(30),
    org_plant_id                VARCHAR(30),
    org_site_id                 VARCHAR(30),
    work_center_id              VARCHAR(80),

    source_system               VARCHAR(80)  NOT NULL DEFAULT 'mom',
    source_aggregate_type       VARCHAR(80)  NOT NULL,
    source_aggregate_id         VARCHAR(160) NOT NULL,
    source_event_id             VARCHAR(160),
    source_record_id            VARCHAR(160),

    so_number                   VARCHAR(80),
    jo_number                   VARCHAR(80),
    wo_number                   VARCHAR(80),
    operation_seq               VARCHAR(40),
    part_number                 VARCHAR(120),
    part_revision               VARCHAR(80),
    lot_number                  VARCHAR(120),
    serial_number               VARCHAR(120),
    parent_lot_number           VARCHAR(120),
    parent_serial_number        VARCHAR(120),
    child_lot_number            VARCHAR(120),
    child_serial_number         VARCHAR(120),

    inspection_id               VARCHAR(120),
    ncr_id                      VARCHAR(120),
    capa_id                     VARCHAR(120),
    scar_id                     VARCHAR(120),
    evidence_id                 VARCHAR(120),
    approval_id                 VARCHAR(120),
    electronic_signature_id     VARCHAR(120),

    actor_id                    VARCHAR(120),
    actor_role                  VARCHAR(120),
    occurred_at                 TIMESTAMPTZ  NOT NULL,
    recorded_at                 TIMESTAMPTZ  NOT NULL DEFAULT now(),
    idempotency_key             VARCHAR(255),
    payload                     JSONB        NOT NULL DEFAULT '{}'::jsonb,
    metadata                    JSONB        NOT NULL DEFAULT '{}'::jsonb,
    row_version                 BIGINT       NOT NULL DEFAULT 1
);

CREATE UNIQUE INDEX IF NOT EXISTS ux_mes_operational_event_idempotency
    ON mes_operational_event_ledger (
        source_system,
        source_aggregate_type,
        source_aggregate_id,
        event_type,
        idempotency_key
    )
    WHERE idempotency_key IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_timeline_wo
    ON mes_operational_event_ledger (wo_number, occurred_at, recorded_at)
    WHERE wo_number IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_timeline_quality
    ON mes_operational_event_ledger (ncr_id, capa_id, occurred_at, recorded_at)
    WHERE ncr_id IS NOT NULL OR capa_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_evidence
    ON mes_operational_event_ledger (evidence_id, occurred_at)
    WHERE evidence_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_genealogy_lot
    ON mes_operational_event_ledger (lot_number, serial_number, occurred_at)
    WHERE lot_number IS NOT NULL OR serial_number IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_correlation
    ON mes_operational_event_ledger (correlation_id, occurred_at, recorded_at);

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_scope
    ON mes_operational_event_ledger (enterprise_id, company_id, site_id, plant_id, occurred_at);

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_org_scope
    ON mes_operational_event_ledger (org_company_code, org_legal_entity_code, org_plant_id, org_site_id, occurred_at);

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_source_aggregate
    ON mes_operational_event_ledger (source_system, source_aggregate_type, source_aggregate_id, occurred_at, recorded_at);

CREATE INDEX IF NOT EXISTS idx_mes_operational_event_payload
    ON mes_operational_event_ledger USING GIN (payload);

COMMENT ON TABLE mes_operational_event_ledger IS
    'Canonical immutable operational event ledger for manufacturing production history and digital-thread timeline queries.';

COMMENT ON COLUMN mes_operational_event_ledger.fingerprint_hash IS
    'SHA-256 hash of the normalized semantic event fingerprint used for idempotent replay/conflict detection.';

COMMENT ON COLUMN mes_operational_event_ledger.event_hash IS
    'SHA-256 hash over the immutable event row payload, excluding this column.';

COMMENT ON COLUMN mes_operational_event_ledger.previous_event_hash IS
    'Previous event hash for the same source aggregate, enabling aggregate-local history chain verification.';

COMMENT ON COLUMN mes_operational_event_ledger.correlation_id IS
    'Business/runtime correlation id used to stitch production, quality, evidence, and genealogy events.';

COMMIT;
-- <<< END MIGRATION: 098_canonical_manufacturing_event_backbone.sql

-- >>> BEGIN MIGRATION: 099_ai_integration_foundation.sql
-- ============================================================================
-- Migration: 099_ai_integration_foundation.sql
-- Description: AI Integration Foundation — chat conversations, feedback loops,
--              training datasets, extended machine telemetry, recommendation
--              action tracking for Phase 1B backend AI integration
-- Dependencies: 041_ai_predictive_quality_aps.sql, 006_erp_master_data.sql
-- Rollback: DROP TABLE ai_recommendation_actions, machine_telemetry_extended,
