CREATE UNIQUE INDEX IF NOT EXISTS ux_plm_change_affected_objects_order_scope
    ON plm_change_affected_objects (
        plm_change_order_id,
        object_type,
        object_id,
        COALESCE(object_revision, ''),
        requested_effect
