-- >>> BEGIN MIGRATION: 128_change_resulting_object_scope_and_snapshot_current.sql
-- ============================================================================
-- Migration 127: Change resulting-object scope and as-manufactured current guard
-- ============================================================================
-- Purpose:
--   Close two data-integrity gaps left after the initial control-plane cutover:
--   1) resulting objects must always be tied to a canonical affected object;
--   2) an as-manufactured subject must have at most one current snapshot.
-- ============================================================================

BEGIN;

UPDATE plm_change_resulting_objects ro
SET affected_object_id = ao.plm_change_affected_object_id
FROM plm_change_affected_objects ao
WHERE ro.affected_object_id IS NULL
  AND ao.plm_change_order_id = ro.plm_change_order_id
  AND lower(ao.object_type) = lower(ro.object_type)
  AND ao.object_id = ro.object_id;

DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM plm_change_resulting_objects
        WHERE affected_object_id IS NULL
    ) THEN
        RAISE EXCEPTION 'plm_change_resulting_objects contains orphan rows; backfill affected_object_id before applying migration 127';
    END IF;
END $$;

ALTER TABLE plm_change_resulting_objects
    ALTER COLUMN affected_object_id SET NOT NULL;

ALTER TABLE effectivity_conflicts
    ADD COLUMN IF NOT EXISTS idempotency_key TEXT,
    ADD COLUMN IF NOT EXISTS metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

CREATE UNIQUE INDEX IF NOT EXISTS ux_effectivity_conflicts_idempotency_key
    ON effectivity_conflicts (idempotency_key)
    WHERE idempotency_key IS NOT NULL;

WITH ranked AS (
    SELECT
        as_manufactured_snapshot_id,
        row_number() OVER (
            PARTITION BY subject_type, subject_ref
            ORDER BY built_at DESC, as_manufactured_snapshot_id DESC
        ) AS rn
    FROM as_manufactured_snapshots
    WHERE snapshot_state = 'current'
)
UPDATE as_manufactured_snapshots s
SET snapshot_state = 'superseded',
    built_at = now(),
    row_version = row_version + 1
FROM ranked r
WHERE s.as_manufactured_snapshot_id = r.as_manufactured_snapshot_id
  AND r.rn > 1;

CREATE UNIQUE INDEX IF NOT EXISTS ux_as_manufactured_snapshots_one_current
    ON as_manufactured_snapshots (subject_type, subject_ref)
    WHERE snapshot_state = 'current';

COMMIT;
-- <<< END MIGRATION: 128_change_resulting_object_scope_and_snapshot_current.sql

-- >>> BEGIN MIGRATION: 129_change_release_authorization_integrity.sql
-- ============================================================================
-- Migration 129: Change release authorization integrity
-- ============================================================================
-- Purpose:
--   Make released change orders and resulting-object links fail closed at the
--   database contract layer, not only in service code.
-- ============================================================================

BEGIN;

ALTER TABLE plm_change_orders
    ADD COLUMN IF NOT EXISTS release_signature_event_id UUID REFERENCES signature_events(signature_event_id),
    ADD COLUMN IF NOT EXISTS release_package_hash_sha256 CHAR(64);

ALTER TABLE genealogy_edge_facts
    ADD COLUMN IF NOT EXISTS org_company_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_legal_entity_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_plant_id VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_site_id VARCHAR(40);

ALTER TABLE frm_submission_attempts
    ADD COLUMN IF NOT EXISTS accepted_at TIMESTAMPTZ,
    ADD COLUMN IF NOT EXISTS accepted_by_ref TEXT,
    ADD COLUMN IF NOT EXISTS acceptance_signature_event_id UUID REFERENCES signature_events(signature_event_id);

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'chk_plm_change_orders_release_signature'
    ) THEN
        ALTER TABLE plm_change_orders
            ADD CONSTRAINT chk_plm_change_orders_release_signature
            CHECK (
                status <> 'released'
                OR (
                    release_signature_event_id IS NOT NULL
                    AND release_package_hash_sha256 IS NOT NULL
                )
            ) NOT VALID;
    END IF;
END $$;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'uq_plm_change_affected_objects_order_id_pair'
    ) THEN
        ALTER TABLE plm_change_affected_objects
            ADD CONSTRAINT uq_plm_change_affected_objects_order_id_pair
            UNIQUE (plm_change_order_id, plm_change_affected_object_id);
    END IF;
END $$;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_plm_change_resulting_objects_same_order_affected'
    ) THEN
        ALTER TABLE plm_change_resulting_objects
            ADD CONSTRAINT fk_plm_change_resulting_objects_same_order_affected
            FOREIGN KEY (plm_change_order_id, affected_object_id)
            REFERENCES plm_change_affected_objects (plm_change_order_id, plm_change_affected_object_id)
            DEFERRABLE INITIALLY DEFERRED;
    END IF;
END $$;

DROP INDEX IF EXISTS ux_as_manufactured_snapshots_one_current;

CREATE UNIQUE INDEX IF NOT EXISTS ux_as_manufactured_snapshots_one_current_scoped
    ON as_manufactured_snapshots (
        subject_type,
        subject_ref,
        COALESCE(org_company_code, ''),
        COALESCE(org_legal_entity_code, ''),
        COALESCE(org_plant_id, ''),
        COALESCE(org_site_id, '')
    )
    WHERE snapshot_state = 'current';

COMMIT;
-- <<< END MIGRATION: 129_change_release_authorization_integrity.sql

-- >>> BEGIN MIGRATION: 130_genealogy_scope_identity_and_5m_gate.sql
-- ============================================================================
-- Migration 130: Genealogy scope identity and production 5M gate closure
-- ============================================================================
-- Purpose:
--   Close the remaining MES/genealogy P1 gaps from the final closure audit:
--   1) node, edge-fact, replay, and cycle identity must be scoped;
--   2) as-manufactured snapshot hash identity must be scoped;
--   3) shopfloor acceptance must have a database contract for 5M gate evidence.
-- ============================================================================

BEGIN;

ALTER TABLE genealogy_edge_facts
    ADD COLUMN IF NOT EXISTS org_company_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_legal_entity_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_plant_id VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_site_id VARCHAR(40);

ALTER TABLE genealogy_nodes
    ADD COLUMN IF NOT EXISTS org_company_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_legal_entity_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_plant_id VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_site_id VARCHAR(40);

ALTER TABLE as_manufactured_snapshots
    ADD COLUMN IF NOT EXISTS org_company_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_legal_entity_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_plant_id VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_site_id VARCHAR(40);

ALTER TABLE shift_production_log
    ADD COLUMN IF NOT EXISTS traceability_5m_gate JSONB NOT NULL DEFAULT '{}'::jsonb,
    ADD COLUMN IF NOT EXISTS traceability_5m_gate_state TEXT GENERATED ALWAYS AS (traceability_5m_gate ->> 'gate_state') STORED,
    ADD COLUMN IF NOT EXISTS traceability_5m_waiver_signature_event_id UUID REFERENCES signature_events(signature_event_id);

DO $$
DECLARE
    constraint_name TEXT;
BEGIN
    FOR constraint_name IN
        SELECT c.conname
        FROM pg_constraint c
        WHERE c.conrelid = 'genealogy_edge_facts'::regclass
          AND c.contype = 'u'
          AND pg_get_constraintdef(c.oid) LIKE '%edge_fact_type%'
          AND pg_get_constraintdef(c.oid) LIKE '%source_event_id%'
    LOOP
        EXECUTE format('ALTER TABLE genealogy_edge_facts DROP CONSTRAINT IF EXISTS %I', constraint_name);
    END LOOP;
END $$;

ALTER TABLE genealogy_nodes
    DROP CONSTRAINT IF EXISTS genealogy_nodes_node_type_node_ref_key;

ALTER TABLE as_manufactured_snapshots
    DROP CONSTRAINT IF EXISTS as_manufactured_snapshots_subject_type_subject_ref_snapshot_hash_sha256_key;

CREATE UNIQUE INDEX IF NOT EXISTS ux_genealogy_edge_facts_scope_source
    ON genealogy_edge_facts (
        edge_fact_type,
        from_object_type,
        from_object_id,
        to_object_type,
        to_object_id,
        source_event_id,
        (COALESCE(org_company_code, '')),
        (COALESCE(org_legal_entity_code, '')),
        (COALESCE(org_plant_id, '')),
        (COALESCE(org_site_id, ''))
    );

CREATE UNIQUE INDEX IF NOT EXISTS ux_genealogy_nodes_scope_identity
    ON genealogy_nodes (
        node_type,
        node_ref,
        (COALESCE(org_company_code, '')),
        (COALESCE(org_legal_entity_code, '')),
        (COALESCE(org_plant_id, '')),
        (COALESCE(org_site_id, ''))
    );

CREATE UNIQUE INDEX IF NOT EXISTS ux_as_manufactured_snapshots_scope_hash
    ON as_manufactured_snapshots (
        subject_type,
        subject_ref,
        snapshot_hash_sha256,
        (COALESCE(org_company_code, '')),
        (COALESCE(org_legal_entity_code, '')),
        (COALESCE(org_plant_id, '')),
        (COALESCE(org_site_id, ''))
    );

DROP INDEX IF EXISTS ux_as_manufactured_snapshots_one_current;

CREATE UNIQUE INDEX IF NOT EXISTS ux_as_manufactured_snapshots_one_current_scoped
    ON as_manufactured_snapshots (
        subject_type,
        subject_ref,
        (COALESCE(org_company_code, '')),
        (COALESCE(org_legal_entity_code, '')),
        (COALESCE(org_plant_id, '')),
        (COALESCE(org_site_id, ''))
    )
    WHERE snapshot_state = 'current';

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'chk_shift_production_log_traceability_5m_gate'
    ) THEN
        ALTER TABLE shift_production_log
            ADD CONSTRAINT chk_shift_production_log_traceability_5m_gate
            CHECK (
                traceability_5m_gate_state IN ('complete', 'waived', 'not_applicable')
                OR traceability_5m_waiver_signature_event_id IS NOT NULL
            ) NOT VALID;
    END IF;
END $$;

COMMENT ON INDEX ux_genealogy_edge_facts_scope_source IS
    'Scope-keyed genealogy fact replay identity; prevents cross-plant/site false conflicts.';

COMMENT ON INDEX ux_genealogy_nodes_scope_identity IS
    'Scope-keyed genealogy node identity for reused lot/order/material refs across plants/sites.';

COMMENT ON INDEX ux_as_manufactured_snapshots_scope_hash IS
    'Scope-keyed as-manufactured snapshot hash identity.';

COMMIT;
-- <<< END MIGRATION: 130_genealogy_scope_identity_and_5m_gate.sql

-- >>> BEGIN MIGRATION: 131_world_class_closure_authority_proof.sql
-- World-class closure: authoritative release ceremonies and gate proof.
--
-- Adds narrowly scoped proof columns/tables required by the closure audit:
-- document controlled-import receipts, training gate signature/evidence proof,
-- and indexes used by audit-pack export retrieval.

BEGIN;

CREATE TABLE IF NOT EXISTS controlled_import_receipts (
    controlled_import_receipt_id TEXT PRIMARY KEY,
    imported_object_type TEXT NOT NULL,
    imported_object_id TEXT,
    receipt_state TEXT NOT NULL DEFAULT 'accepted'
        CHECK (receipt_state IN ('draft', 'accepted', 'rejected', 'voided')),
    source_system TEXT NOT NULL DEFAULT 'controlled_import',
    manifest_hash_sha256 CHAR(64) NOT NULL,
    imported_by_ref TEXT NOT NULL,
    accepted_at TIMESTAMPTZ,
    source_change_order_id UUID REFERENCES plm_change_orders(plm_change_order_id),
    metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    row_version BIGINT NOT NULL DEFAULT 1,
    CHECK (receipt_state <> 'accepted' OR accepted_at IS NOT NULL)
);

CREATE INDEX IF NOT EXISTS idx_controlled_import_receipts_object
    ON controlled_import_receipts (imported_object_type, imported_object_id, receipt_state);

ALTER TABLE plm_change_training_requirements
    ADD COLUMN IF NOT EXISTS satisfaction_signature_event_id UUID REFERENCES signature_events(signature_event_id),
    ADD COLUMN IF NOT EXISTS waiver_signature_event_id UUID REFERENCES signature_events(signature_event_id),
    ADD COLUMN IF NOT EXISTS training_evidence_record_id UUID REFERENCES evidence_records(evidence_record_id),
    ADD COLUMN IF NOT EXISTS source_training_record_id TEXT;

ALTER TABLE plm_change_training_requirements
    DROP CONSTRAINT IF EXISTS ck_plm_change_training_authoritative_completion;

ALTER TABLE plm_change_training_requirements
    ADD CONSTRAINT ck_plm_change_training_authoritative_completion
    CHECK (
        requirement_state NOT IN ('satisfied', 'waived')
        OR satisfaction_signature_event_id IS NOT NULL
        OR waiver_signature_event_id IS NOT NULL
        OR training_evidence_record_id IS NOT NULL
        OR NULLIF(trim(source_training_record_id), '') IS NOT NULL
        OR NULLIF(trim(COALESCE(metadata ->> 'authoritative_training_decision_id', '')), '') IS NOT NULL
    );

CREATE INDEX IF NOT EXISTS idx_audit_pack_exports_scope_lookup
    ON audit_pack_exports (export_scope, scope_ref, completed_at DESC);

CREATE INDEX IF NOT EXISTS idx_audit_pack_exports_package_hash
    ON audit_pack_exports (package_hash_sha256)
    WHERE package_hash_sha256 IS NOT NULL;

COMMIT;
-- <<< END MIGRATION: 131_world_class_closure_authority_proof.sql

-- >>> BEGIN MIGRATION: 132_world_class_closure_reaudit_integrity.sql
-- ============================================================================
-- Migration 132: World-class closure re-audit integrity hardening
-- ============================================================================
-- Purpose:
--   Close the remaining P1 findings from the April 2026 closure re-audit:
--   1) e-signature rows must be relationally tied to consumed challenges;
--   2) explicit field authorization tokens are one-shot service authorities.
-- ============================================================================

BEGIN;

CREATE INDEX IF NOT EXISTS idx_signature_events_auth_challenge_id
    ON signature_events (auth_challenge_id)
    WHERE auth_challenge_id IS NOT NULL;

DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM signature_events se
        LEFT JOIN e_signature_auth_challenges ac
          ON ac.auth_challenge_id = se.auth_challenge_id
        WHERE se.auth_challenge_id IS NOT NULL
          AND ac.auth_challenge_id IS NULL
    ) THEN
        RAISE EXCEPTION 'signature_events_auth_challenge_orphans_block_fk';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_signature_events_auth_challenge'
    ) THEN
        ALTER TABLE signature_events
            ADD CONSTRAINT fk_signature_events_auth_challenge
            FOREIGN KEY (auth_challenge_id)
            REFERENCES e_signature_auth_challenges (auth_challenge_id)
            DEFERRABLE INITIALLY IMMEDIATE;
    END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_eqms_field_change_authorization_unconsumed
    ON eqms_field_change_authorization (
        plm_change_order_id,
        lower(object_type),
        object_id,
        field_path,
        authorized_effect,
        authorized_from DESC
    )
    WHERE consumed_at IS NULL;

COMMENT ON CONSTRAINT fk_signature_events_auth_challenge ON signature_events IS
    'Part 11 closure control: every signature event carrying an auth_challenge_id must link to a recorded e-signature challenge.';

COMMENT ON INDEX idx_eqms_field_change_authorization_unconsumed IS
    'Lookup index for one-shot explicit field authorization tokens; service consumes matching rows atomically before allowing governed edits.';

COMMIT;
-- <<< END MIGRATION: 132_world_class_closure_reaudit_integrity.sql

-- >>> BEGIN MIGRATION: 133_world_class_closure_scope_change_integrity.sql
-- ============================================================================
-- Migration 133: World-class closure scope and change integrity hardening
-- ============================================================================
-- Purpose:
--   Close residual P1 audit gaps for scoped 5M obligations, released change-order
--   signature validation, released document/form immutability, and periodic
--   evaluation waiver signature proof.
-- ============================================================================

BEGIN;

-- 1) Validate released change orders cannot remain released without signature
--    proof and a release-package hash.
DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM plm_change_orders
        WHERE status = 'released'
          AND (release_signature_event_id IS NULL OR release_package_hash_sha256 IS NULL)
    ) THEN
        RAISE EXCEPTION 'plm_change_orders_release_signature_unvalidated_rows_block_constraint';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'chk_plm_change_orders_release_signature'
    ) THEN
        ALTER TABLE plm_change_orders
            ADD CONSTRAINT chk_plm_change_orders_release_signature
            CHECK (
                status <> 'released'
                OR (
                    release_signature_event_id IS NOT NULL
                    AND release_package_hash_sha256 IS NOT NULL
                )
            );
    ELSE
        ALTER TABLE plm_change_orders
            VALIDATE CONSTRAINT chk_plm_change_orders_release_signature;
    END IF;
END $$;

-- 2) Scope 5M obligations by company/legal entity/plant/site so one plant cannot
--    satisfy or contaminate another plant's traceability gate.
ALTER TABLE traceability_5m_obligations
    ADD COLUMN IF NOT EXISTS org_company_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_legal_entity_code VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_plant_id VARCHAR(40),
    ADD COLUMN IF NOT EXISTS org_site_id VARCHAR(40);

ALTER TABLE traceability_5m_obligations
    DROP CONSTRAINT IF EXISTS traceability_5m_obligations_operation_class_object_type_object_id_key;

CREATE UNIQUE INDEX IF NOT EXISTS ux_traceability_5m_obligations_scoped
    ON traceability_5m_obligations (
        operation_class,
        object_type,
        object_id,
        (COALESCE(org_company_code::text, '')),
        (COALESCE(org_legal_entity_code::text, '')),
        (COALESCE(org_plant_id::text, '')),
        (COALESCE(org_site_id::text, ''))
    );

-- 3) Released/terminal document and form-control records are immutable at the DB
--    contract layer for content/hash/schema/render-policy fields.
CREATE OR REPLACE FUNCTION prevent_released_document_form_control_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF TG_TABLE_NAME = 'doc_revisions'
           AND OLD.lifecycle_state IN ('released', 'superseded', 'obsolete', 'withdrawn') THEN
            RAISE EXCEPTION 'released_doc_revision_delete_blocked';
        END IF;
        IF TG_TABLE_NAME = 'frm_template_revisions'
           AND OLD.lifecycle_state IN ('released', 'superseded', 'obsolete', 'withdrawn') THEN
            RAISE EXCEPTION 'released_form_template_revision_delete_blocked';
        END IF;
        IF TG_TABLE_NAME = 'frm_schema_versions'
           AND OLD.lifecycle_state IN ('released', 'superseded', 'withdrawn') THEN
            RAISE EXCEPTION 'released_form_schema_version_delete_blocked';
        END IF;
        RETURN OLD;
    END IF;

    IF TG_TABLE_NAME = 'doc_revisions'
       AND OLD.lifecycle_state IN ('released', 'superseded', 'obsolete', 'withdrawn')
       AND (
           NEW.doc_family_id IS DISTINCT FROM OLD.doc_family_id
           OR NEW.revision_label IS DISTINCT FROM OLD.revision_label
           OR NEW.revision_sequence IS DISTINCT FROM OLD.revision_sequence
           OR NEW.source_change_order_id IS DISTINCT FROM OLD.source_change_order_id
           OR NEW.canonical_payload IS DISTINCT FROM OLD.canonical_payload
           OR NEW.readable_snapshot_uri IS DISTINCT FROM OLD.readable_snapshot_uri
           OR NEW.manifest_hash_sha256 IS DISTINCT FROM OLD.manifest_hash_sha256
           OR NEW.approved_by IS DISTINCT FROM OLD.approved_by
           OR NEW.approved_at IS DISTINCT FROM OLD.approved_at
           OR NEW.released_at IS DISTINCT FROM OLD.released_at
           OR NEW.superseded_by_revision_id IS DISTINCT FROM OLD.superseded_by_revision_id
           OR NEW.metadata IS DISTINCT FROM OLD.metadata
       ) THEN
        RAISE EXCEPTION 'released_doc_revision_immutable';
    END IF;

    IF TG_TABLE_NAME = 'frm_template_revisions'
       AND OLD.lifecycle_state IN ('released', 'superseded', 'obsolete', 'withdrawn')
       AND (
           NEW.frm_family_id IS DISTINCT FROM OLD.frm_family_id
           OR NEW.template_revision IS DISTINCT FROM OLD.template_revision
           OR NEW.revision_sequence IS DISTINCT FROM OLD.revision_sequence
           OR NEW.source_doc_revision_id IS DISTINCT FROM OLD.source_doc_revision_id
           OR NEW.source_change_order_id IS DISTINCT FROM OLD.source_change_order_id
           OR NEW.template_storage_uri IS DISTINCT FROM OLD.template_storage_uri
           OR NEW.template_checksum_sha256 IS DISTINCT FROM OLD.template_checksum_sha256
           OR NEW.naming_policy IS DISTINCT FROM OLD.naming_policy
           OR NEW.issuance_policy IS DISTINCT FROM OLD.issuance_policy
           OR NEW.manifest_hash_sha256 IS DISTINCT FROM OLD.manifest_hash_sha256
           OR NEW.released_at IS DISTINCT FROM OLD.released_at
           OR NEW.metadata IS DISTINCT FROM OLD.metadata
       ) THEN
        RAISE EXCEPTION 'released_form_template_revision_immutable';
    END IF;

    IF TG_TABLE_NAME = 'frm_schema_versions'
       AND OLD.lifecycle_state IN ('released', 'superseded', 'withdrawn')
       AND (
           NEW.frm_template_revision_id IS DISTINCT FROM OLD.frm_template_revision_id
           OR NEW.schema_version IS DISTINCT FROM OLD.schema_version
           OR NEW.schema_sequence IS DISTINCT FROM OLD.schema_sequence
           OR NEW.json_schema IS DISTINCT FROM OLD.json_schema
           OR NEW.canonicalization_rules IS DISTINCT FROM OLD.canonicalization_rules
           OR NEW.validation_rules IS DISTINCT FROM OLD.validation_rules
           OR NEW.render_profile IS DISTINCT FROM OLD.render_profile
           OR NEW.source_change_order_id IS DISTINCT FROM OLD.source_change_order_id
           OR NEW.metadata IS DISTINCT FROM OLD.metadata
       ) THEN
        RAISE EXCEPTION 'released_form_schema_version_immutable';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_doc_revisions_released_immutable ON doc_revisions;
CREATE TRIGGER trg_doc_revisions_released_immutable
    BEFORE UPDATE ON doc_revisions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

DROP TRIGGER IF EXISTS trg_doc_revisions_released_delete_immutable ON doc_revisions;
CREATE TRIGGER trg_doc_revisions_released_delete_immutable
    BEFORE DELETE ON doc_revisions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

DROP TRIGGER IF EXISTS trg_frm_template_revisions_released_immutable ON frm_template_revisions;
CREATE TRIGGER trg_frm_template_revisions_released_immutable
    BEFORE UPDATE ON frm_template_revisions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

DROP TRIGGER IF EXISTS trg_frm_template_revisions_released_delete_immutable ON frm_template_revisions;
CREATE TRIGGER trg_frm_template_revisions_released_delete_immutable
    BEFORE DELETE ON frm_template_revisions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

DROP TRIGGER IF EXISTS trg_frm_schema_versions_released_immutable ON frm_schema_versions;
CREATE TRIGGER trg_frm_schema_versions_released_immutable
    BEFORE UPDATE ON frm_schema_versions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

DROP TRIGGER IF EXISTS trg_frm_schema_versions_released_delete_immutable ON frm_schema_versions;
CREATE TRIGGER trg_frm_schema_versions_released_delete_immutable
    BEFORE DELETE ON frm_schema_versions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_released_document_form_control_mutation();

-- 4) Periodic evaluation waivers must reference a real e-signature event.
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_periodic_evaluations_waiver_signature_event'
    ) THEN
        ALTER TABLE periodic_evaluations
            ADD CONSTRAINT fk_periodic_evaluations_waiver_signature_event
            FOREIGN KEY (waiver_signature_event_id)
            REFERENCES signature_events(signature_event_id);
    END IF;
END $$;

-- 5) Register the digest worker as a governed background job pattern. Runtime
--    scheduling still owns exact cadence, but the handler key is now controlled.
INSERT INTO background_jobs (job_type, job_state, priority, payload, idempotency_key)
VALUES (
    'audit.integrity_digest.daily',
    'queued',
    50,
    '{"handler_key":"audit.integrity_digest.daily","scopes":[{}],"authority":"migration_133_world_class_closure","worker":"IntegrityDigestWorker"}'::jsonb,
    'system|audit.integrity_digest.daily|registry'
)
ON CONFLICT (idempotency_key) DO UPDATE
SET payload = EXCLUDED.payload,
    updated_at = now();

COMMIT;
-- <<< END MIGRATION: 133_world_class_closure_scope_change_integrity.sql

-- >>> BEGIN MIGRATION: 134_world_class_closure_final_record_integrity.sql
-- ============================================================================
-- Migration 134: World-class closure final record integrity hardening
-- ============================================================================
-- Purpose:
--   Close the remaining P1 control gaps from the 2026-04-15 re-audit:
--   1) regulated applied signatures must be backed by a full e-sign ceremony;
--   2) finalized evidence record headers must be immutable;
--   3) integrity digest evidence must be append-only;
--   4) active retention locks must not be mutated or deleted outside a future
--      governed disposition service.
-- ============================================================================

BEGIN;

DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM signature_events
        WHERE signature_state = 'applied'
          AND lower(replace(signature_meaning, ' ', '_')) IN (
              'evidence_finalize',
              'document_release',
              'document_read_acknowledgement',
              'form_submission_acceptance',
              'periodic_evaluation_waiver',
              'change_order_release',
              'verification_waiver'
          )
          AND (
              NULLIF(trim(COALESCE(auth_challenge_id, '')), '') IS NULL
              OR NULLIF(trim(COALESCE(auth_method, '')), '') IS NULL
              OR auth_result_hash_sha256 IS NULL
              OR signer_identity_snapshot = '{}'::jsonb
              OR displayed_record_hash_sha256 IS NULL
              OR NULLIF(trim(COALESCE(signature_manifestation, '')), '') IS NULL
          )
    ) THEN
        RAISE EXCEPTION 'signature_events_applied_regulated_ceremony_unvalidated_rows';
    END IF;
END $$;

ALTER TABLE signature_events
    DROP CONSTRAINT IF EXISTS chk_signature_events_applied_regulated_ceremony;

ALTER TABLE signature_events
    ADD CONSTRAINT chk_signature_events_applied_regulated_ceremony
    CHECK (
        signature_state <> 'applied'
        OR lower(replace(signature_meaning, ' ', '_')) NOT IN (
            'evidence_finalize',
            'document_release',
            'document_read_acknowledgement',
            'form_submission_acceptance',
            'periodic_evaluation_waiver',
            'change_order_release',
            'verification_waiver'
        )
        OR (
            NULLIF(trim(COALESCE(auth_challenge_id, '')), '') IS NOT NULL
            AND NULLIF(trim(COALESCE(auth_method, '')), '') IS NOT NULL
            AND auth_result_hash_sha256 IS NOT NULL
            AND signer_identity_snapshot <> '{}'::jsonb
            AND displayed_record_hash_sha256 IS NOT NULL
            AND NULLIF(trim(COALESCE(signature_manifestation, '')), '') IS NOT NULL
        )
    );

CREATE OR REPLACE FUNCTION prevent_final_evidence_record_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF OLD.record_state IN ('finalized', 'superseded', 'voided', 'retained', 'legal_hold') THEN
            RAISE EXCEPTION 'final_evidence_record_delete_blocked';
        END IF;
        RETURN OLD;
    END IF;

    IF OLD.record_state IN ('finalized', 'superseded', 'voided', 'retained', 'legal_hold')
       AND (
           NEW.evidence_key IS DISTINCT FROM OLD.evidence_key
           OR NEW.subject_type IS DISTINCT FROM OLD.subject_type
           OR NEW.subject_id IS DISTINCT FROM OLD.subject_id
           OR NEW.source_issuance_id IS DISTINCT FROM OLD.source_issuance_id
           OR NEW.source_attempt_id IS DISTINCT FROM OLD.source_attempt_id
           OR NEW.current_version_id IS DISTINCT FROM OLD.current_version_id
           OR NEW.retention_class IS DISTINCT FROM OLD.retention_class
           OR NEW.metadata IS DISTINCT FROM OLD.metadata
       ) THEN
        RAISE EXCEPTION 'final_evidence_record_immutable';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_evidence_records_final_immutable ON evidence_records;
CREATE TRIGGER trg_evidence_records_final_immutable
    BEFORE UPDATE ON evidence_records
    FOR EACH ROW
    EXECUTE FUNCTION prevent_final_evidence_record_mutation();

DROP TRIGGER IF EXISTS trg_evidence_records_final_delete_immutable ON evidence_records;
CREATE TRIGGER trg_evidence_records_final_delete_immutable
    BEFORE DELETE ON evidence_records
    FOR EACH ROW
    EXECUTE FUNCTION prevent_final_evidence_record_mutation();

CREATE OR REPLACE FUNCTION prevent_integrity_digest_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        RAISE EXCEPTION 'integrity_digest_delete_blocked';
    END IF;
    RAISE EXCEPTION 'integrity_digest_immutable';
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_integrity_digests_immutable ON integrity_digests;
CREATE TRIGGER trg_integrity_digests_immutable
    BEFORE UPDATE ON integrity_digests
    FOR EACH ROW
    EXECUTE FUNCTION prevent_integrity_digest_mutation();

DROP TRIGGER IF EXISTS trg_integrity_digests_delete_immutable ON integrity_digests;
CREATE TRIGGER trg_integrity_digests_delete_immutable
    BEFORE DELETE ON integrity_digests
    FOR EACH ROW
    EXECUTE FUNCTION prevent_integrity_digest_mutation();

CREATE OR REPLACE FUNCTION prevent_integrity_exception_identity_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        RAISE EXCEPTION 'integrity_exception_delete_blocked';
    END IF;

    IF NEW.integrity_digest_id IS DISTINCT FROM OLD.integrity_digest_id
       OR NEW.object_type IS DISTINCT FROM OLD.object_type
       OR NEW.object_id IS DISTINCT FROM OLD.object_id
       OR NEW.severity IS DISTINCT FROM OLD.severity
       OR NEW.reason_code IS DISTINCT FROM OLD.reason_code
       OR NEW.description IS DISTINCT FROM OLD.description
       OR NEW.opened_by_user_id IS DISTINCT FROM OLD.opened_by_user_id
       OR NEW.opened_at IS DISTINCT FROM OLD.opened_at THEN
        RAISE EXCEPTION 'integrity_exception_identity_immutable';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_integrity_exceptions_identity_immutable ON integrity_exceptions;
CREATE TRIGGER trg_integrity_exceptions_identity_immutable
    BEFORE UPDATE ON integrity_exceptions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_integrity_exception_identity_mutation();

DROP TRIGGER IF EXISTS trg_integrity_exceptions_delete_immutable ON integrity_exceptions;
CREATE TRIGGER trg_integrity_exceptions_delete_immutable
    BEFORE DELETE ON integrity_exceptions
    FOR EACH ROW
    EXECUTE FUNCTION prevent_integrity_exception_identity_mutation();

CREATE OR REPLACE FUNCTION prevent_active_retention_lock_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF OLD.lock_state = 'active' THEN
            RAISE EXCEPTION 'active_retention_lock_delete_blocked';
        END IF;
        RETURN OLD;
    END IF;

    IF OLD.lock_state = 'active' THEN
        RAISE EXCEPTION 'active_retention_lock_immutable';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_retention_locks_active_immutable ON retention_locks;
CREATE TRIGGER trg_retention_locks_active_immutable
    BEFORE UPDATE ON retention_locks
    FOR EACH ROW
    EXECUTE FUNCTION prevent_active_retention_lock_mutation();

DROP TRIGGER IF EXISTS trg_retention_locks_active_delete_immutable ON retention_locks;
CREATE TRIGGER trg_retention_locks_active_delete_immutable
    BEFORE DELETE ON retention_locks
    FOR EACH ROW
    EXECUTE FUNCTION prevent_active_retention_lock_mutation();

COMMENT ON CONSTRAINT chk_signature_events_applied_regulated_ceremony ON signature_events IS
    'Regulated applied signatures must include challenge, auth method, result hash, signer identity, displayed hash, and manifestation proof.';

COMMIT;
-- <<< END MIGRATION: 134_world_class_closure_final_record_integrity.sql

-- >>> BEGIN MIGRATION: 135_world_class_mes_event_spine_periodic_closure.sql
-- ============================================================================
-- Migration 135: World-Class MES Event Spine and Periodic Evaluation Closure
-- ============================================================================
-- Purpose:
--   Close second re-audit P1 gaps:
--   - Periodic evaluations need first-class org partitioning, terminal-row
--     immutability, and append-only closure proof.
--   - MTConnect/OPC-UA style machine ingestion needs a real append-only raw
--     event spine plus deterministic production derivation ledger.
-- ============================================================================

BEGIN;

-- 1) Periodic evaluation scope must be schema-enforced, not hidden in JSON.
ALTER TABLE periodic_evaluations
    ADD COLUMN IF NOT EXISTS org_id TEXT;

UPDATE periodic_evaluations
SET org_id = COALESCE(NULLIF(org_id, ''), NULLIF(result_payload->>'org_id', ''), 'default-org')
WHERE org_id IS NULL OR org_id = '';

ALTER TABLE periodic_evaluations
    ALTER COLUMN org_id SET NOT NULL;

ALTER TABLE periodic_evaluations
    DROP CONSTRAINT IF EXISTS periodic_evaluations_evaluation_scope_scope_ref_due_at_key;

CREATE UNIQUE INDEX IF NOT EXISTS ux_periodic_evaluations_org_scope_due
    ON periodic_evaluations (org_id, evaluation_scope, scope_ref, due_at);

CREATE INDEX IF NOT EXISTS idx_periodic_evaluations_org_state_due
    ON periodic_evaluations (org_id, evaluation_state, due_at);

CREATE TABLE IF NOT EXISTS periodic_evaluation_closure_events (
    periodic_evaluation_closure_event_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    periodic_evaluation_id UUID NOT NULL REFERENCES periodic_evaluations(periodic_evaluation_id),
    org_id TEXT NOT NULL,
    terminal_state TEXT NOT NULL CHECK (terminal_state IN ('passed', 'failed', 'waived')),
    closure_payload JSONB NOT NULL DEFAULT '{}'::jsonb,
    closure_payload_hash_sha256 TEXT NOT NULL CHECK (closure_payload_hash_sha256 ~ '^[a-f0-9]{64}$'),
    integrity_digest_id UUID REFERENCES integrity_digests(integrity_digest_id),
    audit_pack_export_id UUID REFERENCES audit_pack_exports(audit_pack_export_id),
    waiver_signature_event_id UUID REFERENCES signature_events(signature_event_id),
    actor_ref TEXT NOT NULL DEFAULT 'system',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (periodic_evaluation_id, terminal_state, closure_payload_hash_sha256)
);

CREATE OR REPLACE FUNCTION prevent_closed_periodic_evaluation_mutation()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF OLD.evaluation_state IN ('passed', 'failed', 'waived') THEN
            RAISE EXCEPTION 'closed_periodic_evaluation_is_immutable';
        END IF;
        RETURN OLD;
    END IF;

    IF OLD.evaluation_state IN ('passed', 'failed', 'waived') THEN
        RAISE EXCEPTION 'closed_periodic_evaluation_is_immutable';
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_periodic_evaluations_closed_immutable ON periodic_evaluations;
CREATE TRIGGER trg_periodic_evaluations_closed_immutable
    BEFORE UPDATE ON periodic_evaluations
    FOR EACH ROW
    EXECUTE FUNCTION prevent_closed_periodic_evaluation_mutation();

DROP TRIGGER IF EXISTS trg_periodic_evaluations_closed_delete_immutable ON periodic_evaluations;
CREATE TRIGGER trg_periodic_evaluations_closed_delete_immutable
    BEFORE DELETE ON periodic_evaluations
    FOR EACH ROW
    EXECUTE FUNCTION prevent_closed_periodic_evaluation_mutation();

CREATE OR REPLACE FUNCTION prevent_append_only_mes_spine_mutation()
RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'mes_event_spine_is_append_only';
END;
$$ LANGUAGE plpgsql;

-- 2) Raw machine event command target for RecordMachineEvent.
CREATE TABLE IF NOT EXISTS machine_raw_events (
    machine_raw_event_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    adapter_id TEXT NOT NULL,
    source_node_id TEXT NOT NULL,
    event_type TEXT NOT NULL,
    source_timestamp TIMESTAMPTZ NOT NULL,
    received_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    quality_code TEXT NOT NULL DEFAULT 'unknown'
        CHECK (quality_code IN ('good', 'questionable', 'unavailable', 'bad', 'unknown')),
    sequence_no TEXT,
    replay_key TEXT NOT NULL,
    raw_payload JSONB NOT NULL,
    raw_payload_hash_sha256 TEXT NOT NULL CHECK (raw_payload_hash_sha256 ~ '^[a-f0-9]{64}$'),
    source_system TEXT NOT NULL DEFAULT 'mom.mes.machine_event_spine',
    source_record_id TEXT,
    org_company_code TEXT,
    org_legal_entity_code TEXT,
    org_plant_id TEXT,
    org_site_id TEXT,
    payload_schema_version TEXT NOT NULL DEFAULT 'mes_machine_raw_event.v1',
    row_version INTEGER NOT NULL DEFAULT 1,
    actor_ref TEXT NOT NULL DEFAULT 'system',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (adapter_id, replay_key)
);

CREATE INDEX IF NOT EXISTS idx_machine_raw_events_source_time
    ON machine_raw_events (source_node_id, source_timestamp DESC);

CREATE INDEX IF NOT EXISTS idx_machine_raw_events_scope_time
    ON machine_raw_events (org_plant_id, org_site_id, source_timestamp DESC);

DROP TRIGGER IF EXISTS trg_machine_raw_events_append_only_update ON machine_raw_events;
CREATE TRIGGER trg_machine_raw_events_append_only_update
    BEFORE UPDATE ON machine_raw_events
    FOR EACH ROW
    EXECUTE FUNCTION prevent_append_only_mes_spine_mutation();

DROP TRIGGER IF EXISTS trg_machine_raw_events_append_only_delete ON machine_raw_events;
CREATE TRIGGER trg_machine_raw_events_append_only_delete
    BEFORE DELETE ON machine_raw_events
    FOR EACH ROW
    EXECUTE FUNCTION prevent_append_only_mes_spine_mutation();

-- 3) Derived production event command target for DeriveProductionEvent.
CREATE TABLE IF NOT EXISTS production_derived_events (
    production_derived_event_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    machine_raw_event_id UUID NOT NULL REFERENCES machine_raw_events(machine_raw_event_id),
    derivation_profile_id TEXT NOT NULL,
    derived_event_type TEXT NOT NULL
        CHECK (derived_event_type IN ('cycle', 'downtime', 'alarm', 'oee_sample', 'state_transition', 'quality_signal')),
    event_time TIMESTAMPTZ NOT NULL,
    replay_key TEXT NOT NULL,
    work_center_id TEXT,
    machine_id TEXT,
    work_order_id TEXT,
    payload JSONB NOT NULL DEFAULT '{}'::jsonb,
    payload_hash_sha256 TEXT NOT NULL CHECK (payload_hash_sha256 ~ '^[a-f0-9]{64}$'),
    actor_ref TEXT NOT NULL DEFAULT 'system',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (machine_raw_event_id, derivation_profile_id, derived_event_type, replay_key)
);

CREATE INDEX IF NOT EXISTS idx_production_derived_events_time
    ON production_derived_events (machine_id, event_time DESC);

DROP TRIGGER IF EXISTS trg_production_derived_events_append_only_update ON production_derived_events;
CREATE TRIGGER trg_production_derived_events_append_only_update
    BEFORE UPDATE ON production_derived_events
    FOR EACH ROW
    EXECUTE FUNCTION prevent_append_only_mes_spine_mutation();

DROP TRIGGER IF EXISTS trg_production_derived_events_append_only_delete ON production_derived_events;
CREATE TRIGGER trg_production_derived_events_append_only_delete
    BEFORE DELETE ON production_derived_events
    FOR EACH ROW
    EXECUTE FUNCTION prevent_append_only_mes_spine_mutation();

INSERT INTO control_plane_command_handlers
    (command_name, handler_key, handler_state, required_role_set, required_guard_set, emitted_event_types)
VALUES
    (
        'RecordMachineEvent',
        'mes.machine_event_spine.record_raw_event',
        'active',
        '["machine_connector","mes_gateway","admin"]'::jsonb,
        '["adapter_identity","source_timestamp","replay_key"]'::jsonb,
        '["machine.raw_event_recorded"]'::jsonb
    ),
    (
        'DeriveProductionEvent',
        'mes.machine_event_spine.derive_production_event',
        'active',
        '["mes_event_worker","admin"]'::jsonb,
        '["raw_event_exists","profile_active","idempotent_derivation"]'::jsonb,
        '["mes.production_event_derived"]'::jsonb
    )
ON CONFLICT (command_name, handler_key) DO UPDATE
SET handler_state = EXCLUDED.handler_state,
    required_role_set = EXCLUDED.required_role_set,
    required_guard_set = EXCLUDED.required_guard_set,
    emitted_event_types = EXCLUDED.emitted_event_types,
    updated_at = now();

COMMIT;
-- <<< END MIGRATION: 135_world_class_mes_event_spine_periodic_closure.sql

-- >>> BEGIN MIGRATION: 136_eqms_worldclass_surface.sql
-- ============================================================================
-- Migration 136: EQMS World-Class Surface Tables
-- ============================================================================
-- Purpose:
--   Add the new tables required for the world-class EQMS expansion in MOM v4.0.
--   Covers: cross-cutting infrastructure (comments, attachments, record-links,
--   signatures, export jobs), plus net-new modules: formal change controls,
--   deviations (expanded), customer complaints (eqms surface), NCR (eqms surface),
--   CAPA (eqms surface), documents (eqms surface), training (eqms surface),
--   audits (eqms surface), supplier quality profiles, quality agreements,
--   supplier audits, SCARs, risk register, MSA studies, lab investigations,
--   batch release, validation projects, field actions, and SPC extensions.
--
-- Dependencies:
--   078_canonical_eqms_compliance_backbone.sql  (document, nonconformance, capa, audit, training, complaint)
--   101_eqms_control_plane_foundation.sql        (audit_events, e-sig, domain_outbox_events)
--
-- Data safety: Additive only. All statements use IF NOT EXISTS / DO NOTHING.
--
-- Rollback (reverse order):
--   DROP TABLE eqms_spc_violation_acks, eqms_field_actions, eqms_batch_release,
--   eqms_validation_executions, eqms_validation_protocols, eqms_validation_requirements,
--   eqms_validation_projects, eqms_lab_investigations, eqms_msa_records,
--   eqms_calibration_records, eqms_risks_controls, eqms_risk_register,
--   eqms_scars, eqms_supplier_audits, eqms_supplier_qualification_events,
--   eqms_quality_agreements, eqms_supplier_profiles, eqms_audit_findings,
--   eqms_audits, eqms_training_matrix, eqms_training_curricula, eqms_training_records,
--   eqms_document_acknowledgements, eqms_controlled_copies, eqms_documents,
--   eqms_capa_records, eqms_ncr_records, eqms_engineering_changes,
--   eqms_change_controls, eqms_deviations, eqms_complaints,
--   eqms_export_jobs, eqms_signatures, eqms_record_links, eqms_attachments,
--   eqms_comments CASCADE;
-- ============================================================================

BEGIN;

-- ── Cross-cutting EQMS Infrastructure ────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_comments (
    comment_id       UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    entity_type      VARCHAR(60) NOT NULL,
    entity_id        UUID        NOT NULL,
    text             TEXT        NOT NULL,
    author           VARCHAR(120) NOT NULL,
    is_internal      BOOLEAN     NOT NULL DEFAULT false,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_comments_entity ON eqms_comments (entity_type, entity_id, created_at DESC);

CREATE TABLE IF NOT EXISTS eqms_attachments (
    attachment_id    UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    entity_type      VARCHAR(60) NOT NULL,
    entity_id        UUID        NOT NULL,
    filename         VARCHAR(512) NOT NULL,
    storage_ref      TEXT        NOT NULL,
    mime_type        VARCHAR(120) NOT NULL DEFAULT 'application/octet-stream',
    size_bytes       BIGINT      NOT NULL DEFAULT 0,
    uploaded_by      VARCHAR(120) NOT NULL,
    uploaded_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_attachments_entity ON eqms_attachments (entity_type, entity_id);

CREATE TABLE IF NOT EXISTS eqms_record_links (
    link_id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    source_type      VARCHAR(60) NOT NULL,
    source_id        UUID        NOT NULL,
    target_type      VARCHAR(60) NOT NULL,
    target_id        UUID        NOT NULL,
    relationship_type VARCHAR(80) NOT NULL DEFAULT 'related',
    linked_by        VARCHAR(120) NOT NULL,
    linked_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (source_type, source_id, target_type, target_id)
);
CREATE INDEX IF NOT EXISTS idx_eqms_record_links_source ON eqms_record_links (source_type, source_id);
CREATE INDEX IF NOT EXISTS idx_eqms_record_links_target ON eqms_record_links (target_type, target_id);

CREATE TABLE IF NOT EXISTS eqms_signatures (
    signature_id     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    entity_type      VARCHAR(60) NOT NULL,
    entity_id        UUID        NOT NULL,
    signer           VARCHAR(120) NOT NULL,
    signing_role     VARCHAR(120),
    reason           TEXT        NOT NULL,
    signed_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
    ip_address       INET
);
CREATE INDEX IF NOT EXISTS idx_eqms_signatures_entity ON eqms_signatures (entity_type, entity_id);

CREATE TABLE IF NOT EXISTS eqms_export_jobs (
    job_id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    module           VARCHAR(80) NOT NULL,
    entity_id        UUID,
    format           VARCHAR(20) NOT NULL DEFAULT 'pdf',
    requested_by     VARCHAR(120) NOT NULL,
    requested_at     TIMESTAMPTZ NOT NULL DEFAULT now(),
    completed_at     TIMESTAMPTZ,
    download_url     TEXT,
    status           VARCHAR(30) NOT NULL DEFAULT 'queued',
    job_params       JSONB       NOT NULL DEFAULT '{}'::jsonb,
    error_message    TEXT
);
CREATE INDEX IF NOT EXISTS idx_eqms_export_jobs_status ON eqms_export_jobs (status, requested_at DESC);

-- ── Customer Complaints (EQMS surface) ──────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_complaints (
    complaint_id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    complaint_number     VARCHAR(80) NOT NULL UNIQUE,
    customer_id          UUID,
    customer_name        VARCHAR(255),
    source               VARCHAR(60) NOT NULL DEFAULT 'customer',   -- customer/field/distributor/internal
    severity             VARCHAR(30) NOT NULL DEFAULT 'minor',       -- minor/major/critical
    category             VARCHAR(80),
    subject              VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    affected_product_id  UUID,
    affected_lot_number  VARCHAR(120),
    affected_qty         NUMERIC(18,4),
    received_date        DATE        NOT NULL,
    assigned_to          VARCHAR(120),
    department           VARCHAR(80),
    priority             VARCHAR(20) NOT NULL DEFAULT 'medium',
    due_date             DATE,
    containment_action   TEXT,
    root_cause           TEXT,
    corrective_action    TEXT,
    preventive_action    TEXT,
    customer_response    TEXT,
    response_sent_at     TIMESTAMPTZ,
    linked_capa_id       UUID,
    linked_field_action_id UUID,
    closed_at            TIMESTAMPTZ,
    closed_by            VARCHAR(120),
    -- 8D fields
    d1_team              JSONB,
    d2_problem           TEXT,
    d3_containment       TEXT,
    d4_root_cause        TEXT,
    d5_corrective        TEXT,
    d6_implementation    TEXT,
    d7_preventive        TEXT,
    d8_recognition       TEXT,
    --
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_complaints_status   ON eqms_complaints (status, received_date DESC);
CREATE INDEX IF NOT EXISTS idx_eqms_complaints_customer ON eqms_complaints (customer_id);

-- ── Deviations / Quality Events ──────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_deviations (
    deviation_id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    deviation_number     VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    severity             VARCHAR(30) NOT NULL DEFAULT 'minor',
    deviation_type       VARCHAR(30) NOT NULL DEFAULT 'unplanned',  -- planned/unplanned/emergency
    department           VARCHAR(80),
    affected_process     VARCHAR(255),
    batch_id             UUID,                                       -- optional batch linkage
    batch_number         VARCHAR(120),
    detected_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    detected_by          VARCHAR(120),
    containment_action   TEXT,
    investigation_summary TEXT,
    root_cause           TEXT,
    linked_capa_id       UUID,
    linked_change_control_id UUID,
    voided_reason        TEXT,
    closed_at            TIMESTAMPTZ,
    closed_by            VARCHAR(120),
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_deviations_status ON eqms_deviations (status, detected_at DESC);
CREATE INDEX IF NOT EXISTS idx_eqms_deviations_batch  ON eqms_deviations (batch_id) WHERE batch_id IS NOT NULL;

-- ── NCR Records (EQMS world-class surface) ──────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_ncr_records (
    ncr_id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    ncr_number           VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    severity             VARCHAR(30) NOT NULL DEFAULT 'minor',
    source               VARCHAR(60) NOT NULL DEFAULT 'production',  -- production/receiving/customer/audit/process
    item_id              UUID,
    job_number           VARCHAR(80),
    lot_number           VARCHAR(120),
    qty_affected         NUMERIC(18,4),
    detected_by          VARCHAR(120),
    detected_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    containment_action   TEXT,
    root_cause           TEXT,
    disposition          VARCHAR(40),                                 -- rework/repair/use_as_is/return_to_vendor/scrap
    disposition_reason   TEXT,
    engineering_justification TEXT,
    mrb_decision         JSONB,
    assigned_to          VARCHAR(120),
    linked_capa_id       UUID,
    closed_at            TIMESTAMPTZ,
    closed_by            VARCHAR(120),
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_ncr_records_status ON eqms_ncr_records (status, detected_at DESC);

-- ── CAPA Records (EQMS world-class surface) ──────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_capa_records (
    capa_id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    capa_number          VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    source_type          VARCHAR(60) NOT NULL DEFAULT 'other',       -- ncr/complaint/audit/deviation/spc/other
    source_id            UUID,
    severity             VARCHAR(30) NOT NULL DEFAULT 'minor',
    root_cause_method    VARCHAR(60),                                 -- 5why/fishbone/fault_tree/other
    root_cause_description TEXT,
    action_plan          JSONB       NOT NULL DEFAULT '[]'::jsonb,   -- array of {desc, responsible, due_date, status}
    assigned_to          VARCHAR(120),
    due_date             DATE,
    effectiveness_criteria TEXT,
    effectiveness_result TEXT,
    approved_by          VARCHAR(120),
    approved_at          TIMESTAMPTZ,
    verification_evidence TEXT,
    cancelled_reason     TEXT,
    closed_at            TIMESTAMPTZ,
    closed_by            VARCHAR(120),
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_capa_records_status    ON eqms_capa_records (status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_eqms_capa_records_source    ON eqms_capa_records (source_type, source_id) WHERE source_id IS NOT NULL;

-- ── Formal Change Controls ────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_change_controls (
    change_control_id    UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    change_control_number VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    change_type          VARCHAR(60) NOT NULL DEFAULT 'process',     -- quality/regulatory/process/product/system/facility
    change_category      VARCHAR(30) NOT NULL DEFAULT 'minor',       -- major/minor/administrative
    justification        TEXT,
    risk_level           VARCHAR(20),                                 -- high/medium/low
    impact_assessment    JSONB,
    approval_route       JSONB       NOT NULL DEFAULT '[]'::jsonb,   -- [{user_id, role, required}]
    approved_by          VARCHAR(120),
    approved_at          TIMESTAMPTZ,
    implementation_plan  TEXT,
    implementation_date  DATE,
    linked_document_ids  JSONB       NOT NULL DEFAULT '[]'::jsonb,
    training_impact_ids  JSONB       NOT NULL DEFAULT '[]'::jsonb,
    effectiveness_criteria TEXT,
    effectiveness_result TEXT,
    closed_at            TIMESTAMPTZ,
    closed_by            VARCHAR(120),
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_change_controls_status ON eqms_change_controls (status, created_at DESC);

-- ── Engineering Changes (EQMS world-class surface) ───────────────────────────

CREATE TABLE IF NOT EXISTS eqms_engineering_changes (
    ec_id                UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    ec_number            VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    description          TEXT        NOT NULL,
    change_category      VARCHAR(60) NOT NULL DEFAULT 'process',     -- design/material/process/tooling/supplier
    reason               TEXT,
    affected_parts       JSONB       NOT NULL DEFAULT '[]'::jsonb,
    affected_bom_ids     JSONB       NOT NULL DEFAULT '[]'::jsonb,
    affected_docs        JSONB       NOT NULL DEFAULT '[]'::jsonb,
    assessment_notes     TEXT,
    assessor             VARCHAR(120),
    assessed_at          TIMESTAMPTZ,
    approved_by          VARCHAR(120),
    approved_at          TIMESTAMPTZ,
    implementation_notes TEXT,
    effective_date       DATE,
    cancellation_reason  TEXT,
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_engineering_changes_status ON eqms_engineering_changes (status, created_at DESC);

-- ── Documents (QualityDocs-grade EQMS surface) ───────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_documents (
    doc_id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    doc_number           VARCHAR(80) NOT NULL UNIQUE,
    title                VARCHAR(512) NOT NULL,
    document_type        VARCHAR(60) NOT NULL DEFAULT 'SOP',         -- SOP/WI/form/policy/spec/record
    department           VARCHAR(80),
    owner                VARCHAR(120),
    revision_code        VARCHAR(20) NOT NULL DEFAULT '00',
    effective_date       DATE,
    expiry_date          DATE,
    storage_ref          TEXT,
    template_id          UUID,
    acknowledgement_required BOOLEAN NOT NULL DEFAULT false,
    content_hash         VARCHAR(128),
    checked_out_by       VARCHAR(120),
    checked_out_at       TIMESTAMPTZ,
    released_by          VARCHAR(120),
    released_at          TIMESTAMPTZ,
    superseded_by        UUID,
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_documents_status      ON eqms_documents (status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_eqms_documents_type_dept   ON eqms_documents (document_type, department);

CREATE TABLE IF NOT EXISTS eqms_controlled_copies (
    copy_id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    doc_id               UUID        NOT NULL REFERENCES eqms_documents(doc_id),
    copy_number          VARCHAR(80) NOT NULL,
    revision_code        VARCHAR(20) NOT NULL,
    issued_to            VARCHAR(120),
    issued_location      VARCHAR(255),
    issued_at            TIMESTAMPTZ NOT NULL DEFAULT now(),
    issued_by            VARCHAR(120),
    retrieved_at         TIMESTAMPTZ,
    status               VARCHAR(30) NOT NULL DEFAULT 'active'
);
CREATE INDEX IF NOT EXISTS idx_eqms_controlled_copies_doc ON eqms_controlled_copies (doc_id);

CREATE TABLE IF NOT EXISTS eqms_document_acknowledgements (
    ack_id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    doc_id               UUID        NOT NULL REFERENCES eqms_documents(doc_id),
    employee_id          VARCHAR(120) NOT NULL,
    employee_name        VARCHAR(255),
    required_by          DATE,
    acknowledged_at      TIMESTAMPTZ,
    acknowledgement_method VARCHAR(60) DEFAULT 'portal',
    status               VARCHAR(30) NOT NULL DEFAULT 'pending',
    UNIQUE (doc_id, employee_id)
);
CREATE INDEX IF NOT EXISTS idx_eqms_doc_acks_doc      ON eqms_document_acknowledgements (doc_id);
CREATE INDEX IF NOT EXISTS idx_eqms_doc_acks_employee ON eqms_document_acknowledgements (employee_id, status);

-- ── Training & Competency (EQMS world-class surface) ─────────────────────────

CREATE TABLE IF NOT EXISTS eqms_training_curricula (
    curriculum_id        UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    curriculum_name      VARCHAR(255) NOT NULL,
    department           VARCHAR(80),
    applicable_roles     JSONB       NOT NULL DEFAULT '[]'::jsonb,
    effective_date       DATE,
    doc_ids              JSONB       NOT NULL DEFAULT '[]'::jsonb,
    renewal_interval_days INTEGER,
    status               VARCHAR(30) NOT NULL DEFAULT 'active',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS eqms_training_records (
    training_id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    training_number      VARCHAR(80) NOT NULL UNIQUE,
    employee_id          VARCHAR(120) NOT NULL,
    employee_name        VARCHAR(255),
    curriculum_id        UUID        REFERENCES eqms_training_curricula(curriculum_id),
    document_id          UUID        REFERENCES eqms_documents(doc_id),
    document_revision    VARCHAR(20),
    training_type        VARCHAR(60) NOT NULL DEFAULT 'read_and_sign', -- read_and_sign/instructor_led/online/on_the_job/exam
    assigned_by          VARCHAR(120),
    assigned_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    due_date             DATE,
    completed_at         TIMESTAMPTZ,
    completion_method    VARCHAR(80),
    assessment_score     NUMERIC(5,2),
    assessment_passed    BOOLEAN,
    effectiveness_criteria TEXT,
    effectiveness_result TEXT,
    waiver_reason        TEXT,
    waiver_approved_by   VARCHAR(120),
    status               VARCHAR(40) NOT NULL DEFAULT 'assigned',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_training_records_employee   ON eqms_training_records (employee_id, status);
CREATE INDEX IF NOT EXISTS idx_eqms_training_records_curriculum ON eqms_training_records (curriculum_id);
CREATE INDEX IF NOT EXISTS idx_eqms_training_records_due        ON eqms_training_records (due_date) WHERE status NOT IN ('completed','verified','expired','waived');

CREATE TABLE IF NOT EXISTS eqms_training_matrix (
    matrix_id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    employee_id          VARCHAR(120) NOT NULL,
    curriculum_id        UUID        NOT NULL REFERENCES eqms_training_curricula(curriculum_id),
    required             BOOLEAN     NOT NULL DEFAULT true,
    completion_status    VARCHAR(30) NOT NULL DEFAULT 'not_started',
    last_completed_at    TIMESTAMPTZ,
    next_due_at          TIMESTAMPTZ,
    UNIQUE (employee_id, curriculum_id)
);
CREATE INDEX IF NOT EXISTS idx_eqms_training_matrix_employee ON eqms_training_matrix (employee_id);

-- ── Audit Management (EQMS world-class surface) ──────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_audits (
    audit_id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    audit_number         VARCHAR(80) NOT NULL UNIQUE,
    audit_type           VARCHAR(30) NOT NULL DEFAULT 'internal',    -- internal/external/supplier/regulatory
    scope                TEXT,
    standard_ref         VARCHAR(80),                                 -- ISO9001/AS9100/IATF/FDA/custom
    lead_auditor         VARCHAR(120),
    team_members         JSONB       NOT NULL DEFAULT '[]'::jsonb,
    auditee_dept         VARCHAR(80),
    planned_date         DATE,
    actual_start         TIMESTAMPTZ,
    actual_end           TIMESTAMPTZ,
    audit_report_ref     TEXT,
    status               VARCHAR(40) NOT NULL DEFAULT 'planned',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_audits_status ON eqms_audits (status, planned_date DESC);

CREATE TABLE IF NOT EXISTS eqms_audit_findings (
    finding_id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    audit_id             UUID        NOT NULL REFERENCES eqms_audits(audit_id),
    finding_number       VARCHAR(20) NOT NULL,
    category             VARCHAR(30) NOT NULL DEFAULT 'minor',       -- major/minor/observation/opportunity
    description          TEXT        NOT NULL,
    clause_reference     VARCHAR(120),
    evidence             TEXT,
    response_required_by DATE,
    responsible_party    VARCHAR(120),
    response             TEXT,
    response_by          VARCHAR(120),
    closed_at            TIMESTAMPTZ,
    status               VARCHAR(30) NOT NULL DEFAULT 'open',
    UNIQUE (audit_id, finding_number)
);
CREATE INDEX IF NOT EXISTS idx_eqms_audit_findings_audit  ON eqms_audit_findings (audit_id, status);

-- ── Supplier Quality Network ──────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_supplier_profiles (
    supplier_profile_id  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    vendor_id            UUID        NOT NULL UNIQUE,
    qualification_status VARCHAR(30) NOT NULL DEFAULT 'under_review', -- qualified/conditional/disqualified/under_review
    qualification_date   DATE,
    requalification_due  DATE,
    risk_tier            VARCHAR(20) NOT NULL DEFAULT 'medium',       -- high/medium/low
    approved_categories  JSONB       NOT NULL DEFAULT '[]'::jsonb,
    quality_agreement_ids JSONB      NOT NULL DEFAULT '[]'::jsonb,
    notes                TEXT,
    disqualification_reason TEXT,
    version              INTEGER     NOT NULL DEFAULT 1,
    updated_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_by           VARCHAR(120)
);
CREATE INDEX IF NOT EXISTS idx_eqms_supplier_profiles_status ON eqms_supplier_profiles (qualification_status);

CREATE TABLE IF NOT EXISTS eqms_supplier_qualification_events (
    event_id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    supplier_profile_id  UUID        NOT NULL REFERENCES eqms_supplier_profiles(supplier_profile_id),
    event_type           VARCHAR(60) NOT NULL,                        -- qualified/disqualified/requalified
    event_date           DATE        NOT NULL,
    recorded_by          VARCHAR(120),
    notes                TEXT,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_supplier_qual_events ON eqms_supplier_qualification_events (supplier_profile_id, event_date DESC);

CREATE TABLE IF NOT EXISTS eqms_quality_agreements (
    agreement_id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    agreement_number     VARCHAR(80) NOT NULL UNIQUE,
    vendor_id            UUID        NOT NULL,
    title                VARCHAR(512) NOT NULL,
    effective_date       DATE        NOT NULL,
    expiry_date          DATE,
    scope                TEXT,
    key_requirements     JSONB       NOT NULL DEFAULT '[]'::jsonb,
    signed_by_supplier   VARCHAR(120),
    signed_at_supplier   DATE,
    signed_by_us         VARCHAR(120),
    signed_at_us         DATE,
    document_ref         TEXT,
    status               VARCHAR(30) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120)
);
CREATE INDEX IF NOT EXISTS idx_eqms_quality_agreements_vendor ON eqms_quality_agreements (vendor_id);

-- ── Supplier Audits + SCAR ────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_supplier_audits (
    supplier_audit_id    UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    supplier_audit_number VARCHAR(80) NOT NULL UNIQUE,
    vendor_id            UUID        NOT NULL,
    audit_scope          TEXT,
    audit_type           VARCHAR(30) NOT NULL DEFAULT 'onsite',       -- onsite/remote/document
    lead_auditor         VARCHAR(120),
    planned_date         DATE,
    actual_start         TIMESTAMPTZ,
    actual_end           TIMESTAMPTZ,
    finding_count        INTEGER     NOT NULL DEFAULT 0,
    scar_ids             JSONB       NOT NULL DEFAULT '[]'::jsonb,
    status               VARCHAR(40) NOT NULL DEFAULT 'planned',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120)
);
CREATE INDEX IF NOT EXISTS idx_eqms_supplier_audits_vendor ON eqms_supplier_audits (vendor_id, status);

CREATE TABLE IF NOT EXISTS eqms_scars (
    scar_id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    scar_number          VARCHAR(80) NOT NULL UNIQUE,
    vendor_id            UUID        NOT NULL,
    supplier_audit_id    UUID        REFERENCES eqms_supplier_audits(supplier_audit_id),
    description          TEXT        NOT NULL,
    priority             VARCHAR(20) NOT NULL DEFAULT 'major',        -- critical/major/minor
    root_cause           TEXT,
    corrective_action_plan TEXT,
    implementation_date  DATE,
    verification_evidence TEXT,
    effectiveness_result TEXT,
    assigned_to          VARCHAR(120),
    assigned_at          TIMESTAMPTZ,
    response_due_date    DATE,
    closed_at            TIMESTAMPTZ,
    status               VARCHAR(40) NOT NULL DEFAULT 'issued',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_scars_vendor ON eqms_scars (vendor_id, status);
CREATE INDEX IF NOT EXISTS idx_eqms_scars_audit  ON eqms_scars (supplier_audit_id) WHERE supplier_audit_id IS NOT NULL;

-- ── Quality Risk Register ─────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_risk_register (
    risk_id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    risk_number          VARCHAR(80) NOT NULL UNIQUE,
    risk_title           VARCHAR(512) NOT NULL,
    risk_description     TEXT,
    risk_category        VARCHAR(60) NOT NULL DEFAULT 'process',     -- product/process/supplier/regulatory/system
    likelihood           SMALLINT    NOT NULL DEFAULT 1 CHECK (likelihood BETWEEN 1 AND 5),
    severity             SMALLINT    NOT NULL DEFAULT 1 CHECK (severity BETWEEN 1 AND 5),
    risk_score           SMALLINT    GENERATED ALWAYS AS (likelihood * severity) STORED,
    residual_risk_score  SMALLINT,
    accepted_by          VARCHAR(120),
    accepted_at          TIMESTAMPTZ,
    acceptance_rationale TEXT,
    review_due           DATE,
    status               VARCHAR(40) NOT NULL DEFAULT 'identified',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_eqms_risk_register_status   ON eqms_risk_register (status, risk_score DESC);

CREATE TABLE IF NOT EXISTS eqms_risks_controls (
    control_id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    risk_id              UUID        NOT NULL REFERENCES eqms_risk_register(risk_id),
    control_description  TEXT        NOT NULL,
    control_type         VARCHAR(30) NOT NULL DEFAULT 'preventive',  -- preventive/detective/corrective
    responsible          VARCHAR(120),
    due_date             DATE,
    verification_evidence TEXT,
    effective            BOOLEAN,
    verified_by          VARCHAR(120),
    verified_at          TIMESTAMPTZ,
    status               VARCHAR(30) NOT NULL DEFAULT 'planned',
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_eqms_risks_controls_risk ON eqms_risks_controls (risk_id);

-- ── MSA Studies ───────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_msa_records (
    msa_id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    msa_number           VARCHAR(80) NOT NULL UNIQUE,
    equipment_id         UUID,
    equipment_name       VARCHAR(255),
    study_type           VARCHAR(60) NOT NULL DEFAULT 'gauge_rr',    -- gauge_rr/linearity/bias/stability
    operator_count       INTEGER,
    part_count           INTEGER,
    repeat_count         INTEGER,
    results              JSONB       NOT NULL DEFAULT '{}'::jsonb,
    grr_percent          NUMERIC(8,4),
    ndc_count            INTEGER,
    passed               BOOLEAN,
    approval_threshold_grr NUMERIC(8,4) NOT NULL DEFAULT 30.0,
    conducted_by         VARCHAR(120),
    conducted_at         TIMESTAMPTZ,
    approved_by          VARCHAR(120),
    approved_at          TIMESTAMPTZ,
    status               VARCHAR(40) NOT NULL DEFAULT 'draft',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120)
);
CREATE INDEX IF NOT EXISTS idx_eqms_msa_records_status ON eqms_msa_records (status);

-- ── Calibration Records (EQMS world-class surface) ───────────────────────────

CREATE TABLE IF NOT EXISTS eqms_calibration_records (
    calibration_id       UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    calibration_number   VARCHAR(80) NOT NULL UNIQUE,
    equipment_id         UUID,
    equipment_name       VARCHAR(255) NOT NULL,
    calibration_standard VARCHAR(255),
    calibration_procedure VARCHAR(255),
    performed_by         VARCHAR(120),
    lab_ref              VARCHAR(120),
    calibration_date     DATE,
    next_due_date        DATE,
    results              JSONB       NOT NULL DEFAULT '{}'::jsonb,
    pass_fail            BOOLEAN,
    oot_declared         BOOLEAN     NOT NULL DEFAULT false,
    oot_reason           TEXT,
    reviewed_by          VARCHAR(120),
    reviewed_at          TIMESTAMPTZ,
    approved_by          VARCHAR(120),
    approved_at          TIMESTAMPTZ,
    certificate_ref      TEXT,
    status               VARCHAR(40) NOT NULL DEFAULT 'scheduled',
    version              INTEGER     NOT NULL DEFAULT 1,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_by           VARCHAR(120)
);
CREATE INDEX IF NOT EXISTS idx_eqms_calibration_equipment ON eqms_calibration_records (equipment_id);
CREATE INDEX IF NOT EXISTS idx_eqms_calibration_status    ON eqms_calibration_records (status, next_due_date ASC);

-- ── Lab Investigations (OOS / OOT) ───────────────────────────────────────────

CREATE TABLE IF NOT EXISTS eqms_lab_investigations (
    investigation_id     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    investigation_number VARCHAR(80) NOT NULL UNIQUE,
    investigation_type   VARCHAR(10) NOT NULL DEFAULT 'OOS' CHECK (investigation_type IN ('OOS','OOT')),
    product_id           UUID,
    lot_number           VARCHAR(120),
    test_name            VARCHAR(255),
    specification        TEXT,
    actual_result        TEXT,
    lab_error_identified BOOLEAN,
